INSERT INTO public."medicine_counts" (id,supplier_id,count,analysis,image_url,created_at,created_by,notes,delivery_document_url,purchase_order_number,expected_quantity,is_partial_delivery,brand_image_urls,lot_expiry_image_urls,receipt_acknowledgment_url,purchase_order_id,product_id) VALUES ('aa696de3-1921-40c6-aac1-38c7f78deb64','275d7ac6-b9d5-487a-a9b2-cc2bc0fa21d9','3','Total de cajas: 3\nDescripción: Las cajas están organizadas de forma algo dispersa sobre una superficie oscura. Una caja está más al frente y a la izquierda, otra está un poco más arriba y al centro, y la tercera está a la derecha, con su lado más largo visible y algo superpuesta con la del centro.\nDetalles relevantes: Las cajas son de color rojo brillante y en algunas de ellas se puede leer "SeDy Fill" o "SeDy" en letra amarilla y blanca. También se aprecian imágenes de alimentos (quizás galletas o cereales) en una de las cajas delanteras. La calidad de la imagen es baja, lo que dificulta discernir detalles más precisos de las etiquetas y el contenido.','https://cjhmbqmhfbspgirnkjkm.supabase.co/storage/v1/object/public/documents/medicine-counts/275d7ac6-b9d5-487a-a9b2-cc2bc0fa21d9_1761526222341.jpg','2025-10-27 00:49:07.205869+00','989165e0-c24f-4360-a1dc-1b84536947b5','Todo ok','https://cjhmbqmhfbspgirnkjkm.supabase.co/storage/v1/object/public/documents/medicine-counts/275d7ac6-b9d5-487a-a9b2-cc2bc0fa21d9_delivery_1761526223473.jpg',NULL,NULL,'false','{}','{}',NULL,NULL,NULL);
INSERT INTO public."medicine_counts" (id,supplier_id,count,analysis,image_url,created_at,created_by,notes,delivery_document_url,purchase_order_number,expected_quantity,is_partial_delivery,brand_image_urls,lot_expiry_image_urls,receipt_acknowledgment_url,purchase_order_id,product_id) VALUES ('33fb82ba-0172-426c-a029-2261cb3cc85c','275d7ac6-b9d5-487a-a9b2-cc2bc0fa21d9','3','Total de cajas: 3\nDescripción: Las cajas están apiladas una detrás de la otra, formando una hilera.\nDetalles: Todas las cajas son idénticas en color (rojo con tapas negras) y tamaño. En el lateral de la caja más cercana se puede leer "CEOY FRL" o algo similar, aunque el texto es difícil de descifrar por completo.','https://cjhmbqmhfbspgirnkjkm.supabase.co/storage/v1/object/public/documents/medicine-counts/275d7ac6-b9d5-487a-a9b2-cc2bc0fa21d9_1761582195077.jpg','2025-10-27 16:21:59.567195+00','989165e0-c24f-4360-a1dc-1b84536947b5','Falta una caja ','https://cjhmbqmhfbspgirnkjkm.supabase.co/storage/v1/object/public/documents/medicine-counts/275d7ac6-b9d5-487a-a9b2-cc2bc0fa21d9_delivery_1761582196052.jpg',NULL,NULL,'false','{}','{}',NULL,NULL,NULL);
INSERT INTO public."medicine_counts" (id,supplier_id,count,analysis,image_url,created_at,created_by,notes,delivery_document_url,purchase_order_number,expected_quantity,is_partial_delivery,brand_image_urls,lot_expiry_image_urls,receipt_acknowledgment_url,purchase_order_id,product_id) VALUES ('ec6b9d67-b087-4195-b044-ac40584e22b4','608f438f-212b-4687-ad33-c401c44e5771','3','Total de cajas: 3\nDescripción: Tres cajas rectangulares, predominantemente rojas con un degradado oscuro en un extremo, están apiladas de forma irregular sobre una superficie oscura. Una de las cajas está encima de las otras dos, que están colocadas una junto a la otra.\n','https://cjhmbqmhfbspgirnkjkm.supabase.co/storage/v1/object/public/documents/medicine-counts/608f438f-212b-4687-ad33-c401c44e5771_1761582338828.jpg','2025-10-27 16:24:23.198365+00','989165e0-c24f-4360-a1dc-1b84536947b5',NULL,'https://cjhmbqmhfbspgirnkjkm.supabase.co/storage/v1/object/public/documents/medicine-counts/608f438f-212b-4687-ad33-c401c44e5771_delivery_1761582339892.jpg',NULL,NULL,'false','{}','{}',NULL,NULL,NULL);
INSERT INTO public."medicine_counts" (id,supplier_id,count,analysis,image_url,created_at,created_by,notes,delivery_document_url,purchase_order_number,expected_quantity,is_partial_delivery,brand_image_urls,lot_expiry_image_urls,receipt_acknowledgment_url,purchase_order_id,product_id) VALUES ('efce8c55-34cc-439f-8909-35d617f28c37','608f438f-212b-4687-ad33-c401c44e5771','86','Total de cajas: 86\nDescripción: Las cajas están organizadas en estantes apilados dentro de lo que parece ser una vitrina o refrigerador. Hay varias marcas y tipos de medicamentos distribuidos en diferentes niveles. En general, hay agrupaciones de cajas de la misma marca y producto, aunque algunas están un poco desordenadas o apiladas de forma irregular.\nDetalles relevantes:\n*   En la parte superior, se ven cajas de "Analgen", "Mensifem", "Espasport" y múltiples cajas de "Syncol" (apiladas en dos pilas).\n*   En el nivel medio-superior, hay cajas de "Dolo-Neurobión" (apiladas) y varias cajas de "Reumophan" (también apiladas).\n*   En el nivel medio-inferior, se observan cajas de "Flanax" en diferentes presentaciones, "Robax", "Advil 12 Horas" y otras cajas de "Advil".\n*   En la parte inferior, hay más cajas de "Flanax" (algunas apiladas y otras sueltas), "Excedrin" (una inclinada) y varias pilas de "Aspirina".\n*   Algunas cajas tienen precios o códigos de barras visibles.','https://cjhmbqmhfbspgirnkjkm.supabase.co/storage/v1/object/public/documents/medicine-counts/608f438f-212b-4687-ad33-c401c44e5771_1761603015122.jpg','2025-10-27 22:09:02.320619+00','989165e0-c24f-4360-a1dc-1b84536947b5',NULL,'https://cjhmbqmhfbspgirnkjkm.supabase.co/storage/v1/object/public/documents/medicine-counts/608f438f-212b-4687-ad33-c401c44e5771_delivery_1761603017684.jpg',NULL,NULL,'false','{}','{}',NULL,NULL,NULL);
INSERT INTO public."medicine_counts" (id,supplier_id,count,analysis,image_url,created_at,created_by,notes,delivery_document_url,purchase_order_number,expected_quantity,is_partial_delivery,brand_image_urls,lot_expiry_image_urls,receipt_acknowledgment_url,purchase_order_id,product_id) VALUES ('8d6c4a53-cccf-43ab-b025-1e4e327eb6b8','69fee263-6b0f-4cd6-ad49-40b78da913b4','4','---\nTotal de cajas: 4\nConfianza: Alto\nCalidad de imagen: Buena\n---\n\nDETALLES DEL ANÁLISIS:\n1.  **Distribución espacial:** Las cajas están organizadas en una única fila horizontal, una al lado de la otra, sobre una superficie plana de madera.\n2.  **Características visibles:** Todas las cajas presentan etiquetas frontales claramente legibles. Se identifican los nombres de los medicamentos (GESENT, RECOPLAT, Norapred), las dosis (ej. 50 mg, 100 mg) y la forma farmacéutica (Inyectable, Tabletas). Los empaques se encuentran en perfecto estado, sin abolladuras ni daños. No se aprecian códigos de barras o QR desde este ángulo.\n3.  **Observaciones importantes:** No se detecta ninguna anomalía. Se trata de cuatro cajas completas y distintas. Es notable que hay dos presentaciones diferentes del mismo medicamento (RECOPLAT).\n4.  **Recomendaciones:** La imagen es de buena calidad y el ángulo es ideal para el conteo. Para futuros inventarios, se recomienda mantener este tipo de fotografía (vista cenital, buena iluminación y sin objetos que obstruyan la visión).','https://cjhmbqmhfbspgirnkjkm.supabase.co/storage/v1/object/public/documents/medicine-counts/69fee263-6b0f-4cd6-ad49-40b78da913b4_1763665449796.jpg','2025-11-20 19:02:40.458198+00','f5e8d07f-183d-4622-9ca1-c71f2c3c47c1','Hola ','https://cjhmbqmhfbspgirnkjkm.supabase.co/storage/v1/object/public/documents/medicine-counts/69fee263-6b0f-4cd6-ad49-40b78da913b4_delivery_1763665452394.jpg','OC_CITIO25-05','10','true','{}','{}',NULL,NULL,NULL);
INSERT INTO public."medicine_counts" (id,supplier_id,count,analysis,image_url,created_at,created_by,notes,delivery_document_url,purchase_order_number,expected_quantity,is_partial_delivery,brand_image_urls,lot_expiry_image_urls,receipt_acknowledgment_url,purchase_order_id,product_id) VALUES ('3667016a-ddae-480b-b66f-ab24a4faccc8','ac6c4582-5a19-49ea-bda7-7bfa3f16dcf0','25','Claro, aquí está el análisis del inventario médico basado en la imagen proporcionada.\n\n---\nTotal de cajas: 25\nConfianza: Medio\nCalidad de imagen: Mala\n---\n\nDETALLES DEL ANÁLISIS:\n1.  **Distribución espacial:** Las cajas están organizadas en un bloque compacto, apiladas en filas y columnas. La mayoría de las cajas (marca Opdivo) están dispuestas en 5 filas de 4 cajas cada una. En el lado derecho, hay otras cajas apiladas y una de frente, rompiendo la uniformidad del bloque principal.\n\n2.  **Características visibles:** Se identifican claramente etiquetas con los nombres de marca de medicamentos de alto costo: "Opdivo", "Tecentriq" y "Keytruda". En las cajas de "Opdivo" se pueden leer parcialmente lo que parecen ser fechas de caducidad (ej. "SEP 2027") y posibles números de lote. Las cajas contadas no presentan daños visibles.\n\n3.  **Observaciones importantes:** La principal limitación es que la imagen no es una fotografía directa del inventario, sino una fotografía de una imagen impresa sobre papel, la cual está sobre una superficie de madera. Esto reduce drásticamente la resolución y la claridad, impidiendo un análisis detallado de las cajas en la parte posterior. Siguiendo las instrucciones de ser conservador, solo se han contado las 25 cajas que son inequívocamente completas y distinguibles. Hay indicios de más cajas detrás de las filas visibles, pero su estado y número no se pueden determinar con certeza.\n\n4.  **Recomendaciones:** Para futuros análisis y obtener un conteo de alta confianza, es crucial tomar fotografías digitales directas del inventario. Las imágenes deben tener alta resolución, buena iluminación y, si es posible, ser tomadas desde varios ángulos para evitar que unas cajas oculten a otras. Evitar fotografiar impresiones o pantallas.','https://cjhmbqmhfbspgirnkjkm.supabase.co/storage/v1/object/public/documents/medicine-counts/ac6c4582-5a19-49ea-bda7-7bfa3f16dcf0_1763666301462.jpg','2025-11-20 19:16:50.907919+00','f5e8d07f-183d-4622-9ca1-c71f2c3c47c1',NULL,NULL,'OC_CITIO25-06','25','false','{}','{}',NULL,NULL,NULL);
INSERT INTO public."medicine_counts" (id,supplier_id,count,analysis,image_url,created_at,created_by,notes,delivery_document_url,purchase_order_number,expected_quantity,is_partial_delivery,brand_image_urls,lot_expiry_image_urls,receipt_acknowledgment_url,purchase_order_id,product_id) VALUES ('b2bdd8b1-5cc8-4d8b-82ae-ab9c8792d4f4','652a8aed-4320-4cff-b91d-3fabd32c707a','4','---\nTotal de cajas: 4\nConfianza: Alto\nCalidad de imagen: Buena\n---\n\nDETALLES DEL ANÁLISIS:\n1.  **Distribución espacial:** Las cajas están dispuestas en una única fila horizontal sobre una superficie de madera, colocadas una al lado de la otra.\n2.  **Características visibles:** Cada una de las cajas es de color blanco y presenta una etiqueta en su cara superior. En estas etiquetas se aprecian claramente códigos alfanuméricos (ej. "1L26042", "R2406211"), fechas (ej. "MAR 27", "JUN 26") y lo que parecen ser valores monetarios. Las cajas se encuentran en buen estado, sin daños visibles.\n3.  **Observaciones importantes:** Se detecta una caja adicional en el extremo izquierdo de la fila que está parcialmente cortada por el borde de la imagen. De acuerdo con las instrucciones, esta caja no se ha incluido en el conteo final al no estar completamente visible.\n4.  **Recomendaciones:** Para garantizar un conteo 100% preciso del lote, es fundamental que la fotografía capture todos los artículos en su totalidad. Se sugiere tomar la imagen desde una mayor distancia o ajustar el encuadre para evitar que los objetos en los bordes queden cortados.','https://cjhmbqmhfbspgirnkjkm.supabase.co/storage/v1/object/public/documents/medicine-counts/652a8aed-4320-4cff-b91d-3fabd32c707a_1763666428852.jpg','2025-11-20 19:18:56.335969+00','f5e8d07f-183d-4622-9ca1-c71f2c3c47c1',NULL,NULL,'OC_CITIO25-07','4','false','{}','{}',NULL,NULL,NULL);
INSERT INTO public."medicine_counts" (id,supplier_id,count,analysis,image_url,created_at,created_by,notes,delivery_document_url,purchase_order_number,expected_quantity,is_partial_delivery,brand_image_urls,lot_expiry_image_urls,receipt_acknowledgment_url,purchase_order_id,product_id) VALUES ('dc9c1065-b868-4394-af82-18d191c8fcad','275d7ac6-b9d5-487a-a9b2-cc2bc0fa21d9','5','---\nTotal de cajas: 5\nConfianza: Alto\nCalidad de imagen: Buena\n---\n\nDETALLES DEL ANÁLISIS:\n1.  **Distribución espacial:** Las cajas están dispuestas sobre una superficie plana y oscura, organizadas en dos filas horizontales. La fila superior contiene una caja y la fila inferior contiene cuatro cajas colocadas una al lado de la otra.\n2.  **Características visibles:** Las etiquetas frontales son claramente legibles. Se identifican los nombres de los medicamentos: "Diclofenaco", "AGRIFEN", "Dimenhidrinato" (marca Aurax), "CAPSIFLU TOTAL" y "GROOBE" (Dimenhidrinato). También se aprecian las dosis (ej. 50 mg, 100 mg) y la cantidad de unidades por caja. No se observan códigos de barras ni QR desde este ángulo.\n3.  **Observaciones importantes:** Se detectan anomalías en el estado de algunas cajas. Las cajas de "Diclofenaco" y "AGRIFEN" están visiblemente abiertas. La caja de "GROOBE" en la esquina inferior derecha presenta un ligero aplastamiento o daño en su estructura.\n4.  **Recomendaciones:** El conteo es preciso desde esta perspectiva. Para un análisis de inventario completo que incluya lotes y fechas de caducidad, sería necesario fotografiar los otros lados de las cajas. Se recomienda almacenar las cajas cerradas para evitar confusiones sobre si el producto ha sido utilizado.','https://cjhmbqmhfbspgirnkjkm.supabase.co/storage/v1/object/public/documents/medicine-counts/275d7ac6-b9d5-487a-a9b2-cc2bc0fa21d9_1763849783201.jpg','2025-11-22 22:16:25.288785+00','f5e8d07f-183d-4622-9ca1-c71f2c3c47c1','Hola hola ','https://cjhmbqmhfbspgirnkjkm.supabase.co/storage/v1/object/public/documents/medicine-counts/275d7ac6-b9d5-487a-a9b2-cc2bc0fa21d9_delivery_1763849784444.jpg','PCT23455','2','false','{}','{}',NULL,NULL,NULL);
INSERT INTO public."messages" (id,from_user_id,to_user_id,subject,message,read,created_at) VALUES ('2bf6c790-ae30-4a34-ba56-ab78c343b97c','ac6c4582-5a19-49ea-bda7-7bfa3f16dcf0','989165e0-c24f-4360-a1dc-1b84536947b5','FACTURA CANCELADA','Buen día, no recibí respuesta del mensaje anterior pero aqui corroboro que la Factura MDS 1614 está cancelada y la misma fue reemplazada por la factura MDS1623 ya que había un error en los lotes de un medicamento. Gracias estoy a la orden.\n\nSofía García \nMEDES','false','2026-03-12 17:18:55.663028+00');
INSERT INTO public."messages" (id,from_user_id,to_user_id,subject,message,read,created_at) VALUES ('840666fc-34ba-4a7c-a837-bafe0ea3e2d5','4912b75c-1c11-4406-b22e-8bc72ee4dc79','989165e0-c24f-4360-a1dc-1b84536947b5','DOCUMENTACION PARA ALTA','Buen día, espero se encuentren bien, me podrian apoyar por favor, estoy subiendo los documentos para darme de alta, pero el sistema no me permite subir la licencia sanitaria, solo tenemos aviso de dispositivos medicos no de funcionamiento, y el ine del representante legal','false','2026-03-18 18:10:22.845307+00');
