INSERT INTO public."messages" (id,from_user_id,to_user_id,subject,message,read,created_at) VALUES ('6b43f275-cb79-4c99-8221-2e0d87a68465','608f438f-212b-4687-ad33-c401c44e5771','989165e0-c24f-4360-a1dc-1b84536947b5','Re: Re: Estoy probando el sistema de mensajes entre proveedores y administracion de QualMedical','Si. Le confirmo recepción de su respuesta.\nProceso a subir documentación para realizar pruebas con la detección de documentos.\nMantengamos la comunicación por este medio para hacer todo el ciclo completo.\n\nAdiós don Pepito.','true','2025-10-22 18:11:18.846104+00');
INSERT INTO public."messages" (id,from_user_id,to_user_id,subject,message,read,created_at) VALUES ('c27bc0b7-e988-44c8-8217-2bd115172a87','989165e0-c24f-4360-a1dc-1b84536947b5','608f438f-212b-4687-ad33-c401c44e5771','Re: Re: Re: Estoy probando el sistema de mensajes entre proveedores y administracion de QualMedical','Que grande Don Pepito.\nAquí Don Jose.\nEspero confirmación de documentos.','true','2025-10-22 18:11:57.601738+00');
