INSERT INTO public."messages" (id,from_user_id,to_user_id,subject,message,read,created_at) VALUES ('99f9c033-b9b1-4034-b471-dde2e949824f','4912b75c-1c11-4406-b22e-8bc72ee4dc79','989165e0-c24f-4360-a1dc-1b84536947b5','DOCUMENTACION PARA ALTA','Buen día, espero se encuentren bien, me podrian apoyar por favor, estoy subiendo los documentos para darme de alta, pero el sistema no me permite subir la licencia sanitaria, solo tenemos aviso de dispositivos medicos no de funcionamiento, y el ine del representante legal','false','2026-03-19 19:41:01.622553+00');
