INSERT INTO public."messages" (id,from_user_id,to_user_id,subject,message,read,created_at) VALUES ('609e7c61-85a9-46cf-b3b6-0fe612b50c06','989165e0-c24f-4360-a1dc-1b84536947b5','275d7ac6-b9d5-487a-a9b2-cc2bc0fa21d9','Re: No hemos recibido la ultima factura','Puede adjuntarla dentro del sistema en la sección factura.\nDeberá adjuntar tambien el xml.\nMuchas gracias.','false','2025-10-27 21:49:21.527116+00');
INSERT INTO public."messages" (id,from_user_id,to_user_id,subject,message,read,created_at) VALUES ('0e9ad629-fcba-406e-b556-1597dfd8ebf6','652a8aed-4320-4cff-b91d-3fabd32c707a','989165e0-c24f-4360-a1dc-1b84536947b5','CARGA DE DOCUMENTOS','Buenas tardes \n\nSe realizo el proceso de subir documentacion para el debido pago de unas facturas, pero es rechazada por la IA. \n\nQuisiera saber si hay otro proceso de validacion de los documentos escaneados?\n\n\nGracias','false','2025-11-25 21:44:17.932743+00');
INSERT INTO public."messages" (id,from_user_id,to_user_id,subject,message,read,created_at) VALUES ('802ef657-c79c-4a22-a5e9-c58dc0e0dc16','989165e0-c24f-4360-a1dc-1b84536947b5','3040f0ae-a60e-4b8c-a1ac-746c13987e41','documentos','Se rechazaron los siguientes documentos comprobante de comicilio y Constancias de Situacion Fiscal los documentos no deben de ser mayor qa un mes de antiguedad.','true','2026-01-16 22:12:47.40185+00');
INSERT INTO public."messages" (id,from_user_id,to_user_id,subject,message,read,created_at) VALUES ('7c61cdae-84ec-41b1-84bf-1df755345292','989165e0-c24f-4360-a1dc-1b84536947b5','f6407529-698d-4ab4-88dd-7fc9f9dccf78','evidencia','Buen día estimado proveedor, le comentamos que falta evidencia en la factura A46','false','2026-02-07 18:40:53.171595+00');
INSERT INTO public."messages" (id,from_user_id,to_user_id,subject,message,read,created_at) VALUES ('0b6bdb2f-4393-41db-bea6-c411c0d37398','ac6c4582-5a19-49ea-bda7-7bfa3f16dcf0','989165e0-c24f-4360-a1dc-1b84536947b5','Factura MDS 1614','Buenos días, hubo un error con la factura MDS 1614 y la vamos a cancelar para tener la facturación correcta. Podrían apoyarnos eliminando de su plataforma la fatura mencionada por favor. \nGracias \n\nSOFIA GARCIA\nMEDES','false','2026-03-04 17:43:42.04374+00');
INSERT INTO public."messages" (id,from_user_id,to_user_id,subject,message,read,created_at) VALUES ('301e670b-5081-446e-befd-cbb8338328cf','8850162c-74af-4b37-8682-4d1dbdefc538','989165e0-c24f-4360-a1dc-1b84536947b5','Propuesta ICU Medical: Consumibles para bombas Plum 360/A+','A quien corresponda,\n\nGusto en saludarle, gracias por darme la oprtunidad de darme de alta en su sistema de proveedores. El motivo del presente mensaje es para comentarle que soy distribuidor autorizado de ICU Medical y les podemos ofrecer sets PlumSet compatibles con bombas Plum 360/A+, con tecnología que minimiza riesgos de error en infusiones (anti-reflujo, filtros avanzados), Registros Sanitarios COFEPRIS e ISO, y precios competitivos con entrega inmediata en CDMX Sur. Centros similares reportan mejoras en seguridad y eficiencia operativa.\n\nMe encuentro disponible para una llamada o de ser posible una cita para poder platicar a detalle la propuesta que les ofrezco y así mismo poder responder cualquier duda que tengan al respecto. \n\nQuedo a sus órdenes y atento a sus comentario.\n\nAtentamente, \n\nJosé Castellanos','false','2026-03-05 01:30:06.41399+00');
